mapper.select:
SELECT m.* FROM ds_member m
WHERE (

        FIND_IN_SET(#{ancestorId}, m.ancestor_path)

)
AND m.status = 1

    AND (

        LENGTH(m.ancestor_path) - LENGTH(REPLACE(m.ancestor_path, ',', '')) = LENGTH(#{ancestorId}) - LENGTH(REPLACE(#{ancestorId}, ',', '')) + #{depth}

    )

ORDER BY m.create_time ASC
